// Validation test for POST /api/route-plan — confirms bad input yields 400.
async function testRoutePlanValidation() {
  const post = (payload) => fetch('http://localhost:3001/api/route-plan', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload)
  });

  // Missing points entirely
  const noPoints = await post({ speed: 6 });
  assertEquals(noPoints.status, 400, 'Missing points should be 400');

  // Too few points (need origin + at least one waypoint)
  const onePoint = await post({ points: [{ lat: 41.35, lon: 2.17 }] });
  assertEquals(onePoint.status, 400, 'A single point should be 400');

  // Out-of-range coordinates
  const badCoords = await post({ points: [{ lat: 41.35, lon: 2.17 }, { lat: 200, lon: 2.5 }] });
  assertEquals(badCoords.status, 400, 'Out-of-range latitude should be 400');

  // Non-numeric coordinates
  const nonNumeric = await post({ points: [{ lat: 41.35, lon: 2.17 }, { lat: 'x', lon: 2.5 }] });
  assertEquals(nonNumeric.status, 400, 'Non-numeric coordinate should be 400');

  // Invalid speed (zero / negative)
  const zeroSpeed = await post({ points: [{ lat: 41.35, lon: 2.17 }, { lat: 41.55, lon: 2.55 }], speed: 0 });
  assertEquals(zeroSpeed.status, 400, 'Zero speed should be 400');

  const negSpeed = await post({ points: [{ lat: 41.35, lon: 2.17 }, { lat: 41.55, lon: 2.55 }], speed: -4 });
  assertEquals(negSpeed.status, 400, 'Negative speed should be 400');
}
